var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"정말 괜찮은 거 맞아? 그 자식이 너한테 나쁜 짓을 하진 않았어?","JPN":"本当に大丈夫なの？　あいつに何か悪いことはされてない？","ENG":"Are you really okay? Did she do anything bad to you?","TWN":"真的沒事嗎？那傢伙沒有對你做壞事吧？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"전 괜찮아요.","JPN":"私は平気です！","ENG":"I'm okay.","TWN":"我沒事。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"제가 만든 샌드위치를 그 애가 한 입 먹고 버린 것만 빼면요.","JPN":"私が作ったサンドイッチをあの子が食べ残したこと以外は。","ENG":"Aside from the fact that she threw away the sandwich I made for her.","TWN":"除了她吃了我做的三明治後又扔掉了之外。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"오오, 진짜잖아?","JPN":"おお、本当だ。","ENG":"Oh, oh, that's really true?","TWN":"哇，真的耶？"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이 음식물의 정체가 뭔진 모르겠지만, 절단면에 이빨 자국이 남아있어.","JPN":"この食べ物の正体はわからないが、切断面に歯形が残っている。","ENG":"I'm not sure what this food is, but there are traces of chewing on the cut surface.","TWN":"雖然不知道這食物的真面目，但切面上留下了咀嚼的痕跡。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"사람을 보고도 무작정 공격하지 않은 데다가, 음식을 먹으려고 시도하다니- 확실히 특이한 케이스네요.","JPN":"人を見てもむやみに攻撃せず、食べ物を食べてみようとするとは、確かに珍しいケースです。","ENG":"She didn't attack you on sight and even tried to eat food. This is definitely an unusual case.","TWN":"看到人也沒有貿然攻擊，還試圖吃東西——確實是個特殊的案例呢。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이 개체는… 인간과 화합하며 살아가기 위해 인간의 음식을 섭취하길 노력했던 게 분명해.","JPN":"この個体は……人間と仲良く生きていくために人間の食べ物を食べようと努力したに違いない。","ENG":"This entity... clearly tried to live in harmony with humans by consuming human food.","TWN":"這個個體……顯然是為了與人類和諧共處而努力嘗試吃人類的食物。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"네? 그거 정말이에요?","JPN":"は？　それって本当ですか？","ENG":"Really? Is that true?","TWN":"啊？那是真的嗎？"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"개인의 헛된 망상일 뿐이니 신경 쓰지 마세요.","JPN":"個人のバカバカしい妄想に過ぎませんので、気にしなくていいですよ。","ENG":"It's just one individual's misguided delusion, so don't pay attention to it.","TWN":"只是個人的妄想而已，不用在意。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"하지만 사람과의 진짜 대화가 가능한 개체라는 건, 이걸로 증명됐군요.","JPN":"でも本当に人と対話できる個体だということは、これで証明されました。","ENG":"But this proves that the entity can truly communicate with humans.","TWN":"但是能夠與人進行真正對話的個體，這一點已經證明了。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"이 침식체는 절대 없애면 안 돼요.","JPN":"この侵食体は絶対倒してはいけません。","ENG":"This C.O. must not be eliminated.","TWN":"這個侵蝕體絕對不能消滅。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"반드시 포획해서 연구해야 합니다.","JPN":"必ず捕獲して研究すべきです。","ENG":"We must capture her and conduct research.","TWN":"必須捕獲進行研究。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"연구가 목적이라면 잔해를 확보하는 것만으로도 충분해요.","JPN":"研究目的なら残骸を確保するだけでも十分です。","ENG":"If the goal is research, securing some remains would be enough.","TWN":"如果目的是研究，只要確保殘骸就足夠了。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"굳이 침식체를 살려두는 위험을 감수할 필요는 없죠.","JPN":"あえて侵食体を生かしておくような危険を冒す必要はありません。","ENG":"There's no need to risk keeping the C.O. alive.","TWN":"沒必要冒著留下侵蝕體的危險。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"크으윽…!","JPN":"くううっ……！","ENG":"Kgh...!","TWN":"呃…！"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"아하하… 다들 진정하세요.","JPN":"あはは……みんな落ち着いて。","ENG":"Ah hah hah... Calm down, everyone.","TWN":"啊哈哈……大家冷靜一下。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_LAUGH"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"음?","JPN":"あら？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"이 화분… 멀쩡하네.","JPN":"この植木鉢……元気だね。","ENG":"This flowerpot... It's intact.","TWN":"這花盆……完好無損。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"솔로베, 이 꽃. 이전에 운석이 추락했을 때도 시든 적 없었지?","JPN":"ソロベー、この花。以前隕石が落下したときも枯れてなかったよね？","ENG":"Solovey, this flower. It didn't wither when the meteorite fell before, right?","TWN":"蘇羅薇，這朵花。之前隕石墜落時也沒有枯萎過吧？"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"네! 지금처럼 싱싱했어요. 물은 꾸준히 줬거든요.","JPN":"あ、はい！　今みたいに生き生きしてました。水やりも忘れませんでしたよ。","ENG":"Yes! It was as fresh as it is now. I never forget to water it.","TWN":"啊，是的！就像現在一樣新鮮。我沒有忘記澆水。"},"stage":{"bg":"ROOM_04","slots":{"L":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"무너진 집을 다시 찾아갔을 때, 그 커다란 식물은 시들고 있었어.","JPN":"壊れた家を再度訪れた時、あの大きな植物は朽ちかけてた。","ENG":"When I went back to the collapsed house, the giant plant was decaying.","TWN":"當我再次找到那座倒塌的房子時，那巨大的植物正在腐爛。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_SERIOUS"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"SEO_YOON_ALT_NULL_PR","text":{"KOREA":"왜 이 꽃만 두 번씩이나 멀쩡한 거지?","JPN":"どうしてこの花だけが2回とも元気なんだろう？","ENG":"But why is it that only this flower remains intact, twice?","TWN":"可是，為什麼那傢伙去過的地方，這朵花竟然兩次都完好無損呢？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_NULL_PR","face":"UNIT_DESPAIR"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"구획 봉쇄가 끝났대요. 태스크포스들이 진을 치고 있으니 안에서 녀석을 찾기만 하면 됩니다.","JPN":"区画封鎖が終わったようです。タスクフォースが陣を張っているので、その中でやつを探してください。","ENG":"The blockade around the block is complete. The TASKFORCEs are stationed, so all we need to do is find her inside.","TWN":"區域封鎖已經結束。特遣勢力正在佈署，只要在裡面找到那傢伙就行了。"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"침식체라면 봐줄 필요 없겠지? 바로 처치해주겠어.","JPN":"侵食体相手に手加減は無用よね？　すぐに倒してやるわ。","ENG":"There's no need to show mercy to a C.O., right? I'll eliminate her right away.","TWN":"如果是侵蝕體的話，就沒必要手下留情了吧？我會立刻解決它。"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"워낙 신출귀몰해서 쉽진 않을 거예요. 도시의 카메라들을 전부 뒤져도 녀석을 못 찾았으니까요.","JPN":"神出鬼没ですからそう簡単には捕まらないと思います。都市のカメラをすべて確認しても見つけられませんでした。","ENG":"She's incredibly elusive, so it won't be simple. Even after checking all the city cameras, we couldn't track her down.","TWN":"她神出鬼沒的，不太好找。我們已經翻遍了城市的所有監視器，也沒能找到她。"},"stage":{"bg":"DONGDAEMUN_DARK","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};